import { useState, useEffect } from "react";

function App() {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [zoom, setZoom] = useState(false);
  const [animatedScore, setAnimatedScore] = useState(0);

  // ✅ NEW STATES (Nothing removed)
  const [darkMode, setDarkMode] = useState(false);
  const [adminMode, setAdminMode] = useState(false);
  const [adminNote, setAdminNote] = useState("");
  const [extraFiles, setExtraFiles] = useState([]);

  const claimId = `CLM-${Date.now()}`;

  /* ---------------- Fraud Score Animation ---------------- */
  useEffect(() => {
    if (result) {
      let start = 0;
      const end = result.fraud_confidence_score || 0;
      const duration = 1200;
      const stepTime = 20;
      const step = (end - start) / (duration / stepTime);

      const interval = setInterval(() => {
        start += step;
        if (start >= end) {
          start = end;
          clearInterval(interval);
        }
        setAnimatedScore(Math.round(start));
      }, stepTime);
    }
  }, [result]);

  /* ---------------- Helper Functions ---------------- */

  const riskLevel = (score) => {
    if (score <= 40) return "Low Risk";
    if (score <= 75) return "Medium Risk";
    return "High Risk";
  };

  const gaugeColor = (score) => {
    if (score <= 50) return "#16a34a";
    if (score <= 80) return "#f59e0b";
    return "#dc2626";
  };

  const verdictColor = (verdict) => {
    if (!verdict) return "#555";
    if (verdict.toLowerCase() === "fraud") return "#dc2626";
    if (verdict.toLowerCase() === "suspicious") return "#f59e0b";
    return "#16a34a";
  };

  /* ---------------- File Handling ---------------- */

  const handleFileChange = (e) => {
    setError(null);
    const selected = e.target.files[0];
    if (!selected) return;

    setFile(selected);
    setPreview(URL.createObjectURL(selected));
    setResult(null);
    setAnimatedScore(0);
  };

  // ✅ Multi image optional support
  const handleExtraFiles = (e) => {
    setExtraFiles([...e.target.files]);
  };

  const handleUpload = async () => {
    if (!file) return setError("Please select an image first.");

    const formData = new FormData();
    formData.append("file", file);

    extraFiles.forEach((f) => formData.append("extra_files", f));

    setLoading(true);
    setResult(null);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", {
        method: "POST",
        body: formData,
      });

      if (!response.ok) throw new Error("Server error");

      const data = await response.json();
      setResult(data);
    } catch (err) {
      setError(err.message || "Something went wrong!");
    }

    setLoading(false);
  };

  const handleReset = () => {
    setFile(null);
    setPreview(null);
    setResult(null);
    setError(null);
    setZoom(false);
    setAnimatedScore(0);
    setExtraFiles([]);
  };

  /* ---------------- ORIGINAL JSON DOWNLOAD (KEPT) ---------------- */

  const downloadReport = () => {
    if (!result) return;
    const blob = new Blob([JSON.stringify(result, null, 2)], {
      type: "application/json",
    });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `audit_report_${claimId}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  /* ---------------- NEW PROFESSIONAL HTML REPORT ---------------- */

  const downloadProfessionalReport = () => {
    if (!result) return;

    const html = `
      <html>
        <head>
          <title>ClaimPilot AI Report</title>
          <style>
            body { font-family: Arial; padding: 40px; }
            h1 { color: #1e40af; }
            .section { margin-top: 20px; }
            .risk { font-weight:bold; }
          </style>
        </head>
        <body>
          <h1>ClaimPilot AI - Audit Report</h1>
          <p><strong>Claim ID:</strong> ${claimId}</p>
          <p><strong>Date:</strong> ${new Date().toLocaleString()}</p>

          <div class="section">
            <h3>Total Estimate</h3>
            <p>PKR ${result.total_estimate_pkr}</p>
          </div>

          <div class="section">
            <h3>Fraud Score</h3>
            <p class="risk">${result.fraud_confidence_score}% - ${riskLevel(
      result.fraud_confidence_score
    )}</p>
          </div>

          <div class="section">
            <h3>Verdict</h3>
            <p>${result.verdict}</p>
          </div>

          <div class="section">
            <h3>Admin Notes</h3>
            <p>${adminNote || "N/A"}</p>
          </div>
        </body>
      </html>
    `;

    const blob = new Blob([html], { type: "text/html" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `ClaimPilot_Report_${claimId}.html`;
    a.click();
    URL.revokeObjectURL(url);
  };

  /* ---------------- THEME SWITCH ---------------- */

  const activeStyles = darkMode ? darkStyles : styles;

  /* ---------------- UI ---------------- */

  return (
    <div style={activeStyles.page}>
      <div style={activeStyles.container}>
        <header style={activeStyles.header}>
          <h1 style={activeStyles.logo}>ClaimPilot AI</h1>
          <p style={activeStyles.tagline}>
            Intelligent Vehicle Damage Assessment & Fraud Detection
          </p>

          {/* ✅ NEW TOGGLES */}
          <div style={{ marginTop: 15 }}>
            <button
              style={activeStyles.toggleBtn}
              onClick={() => setDarkMode(!darkMode)}
            >
              {darkMode ? "Light Mode" : "Dark Mode"}
            </button>

            <button
              style={{ ...activeStyles.toggleBtn, marginLeft: 10 }}
              onClick={() => setAdminMode(!adminMode)}
            >
              {adminMode ? "User Mode" : "Admin Mode"}
            </button>
          </div>

          <div style={activeStyles.status}>
            <span style={activeStyles.dot}></span> AI System Active
          </div>
        </header>

        {/* Upload Card */}
        <div style={activeStyles.uploadCard}>
          {preview && (
            <img
              src={preview}
              alt="preview"
              style={zoom ? activeStyles.previewZoom : activeStyles.preview}
              onClick={() => setZoom(!zoom)}
            />
          )}

          <label style={activeStyles.uploadLabel}>
            {file ? file.name : "Click or Drag Image Here"}
            <input
              type="file"
              accept="image/*"
              style={{ display: "none" }}
              onChange={handleFileChange}
            />
          </label>

          {/* ✅ Multi image input (optional) */}
          <input
            type="file"
            multiple
            onChange={handleExtraFiles}
            style={{ marginBottom: 15 }}
          />

          <div style={activeStyles.buttonRow}>
            <button
              onClick={handleUpload}
              disabled={loading}
              style={loading ? activeStyles.disabledBtn : activeStyles.primaryBtn}
            >
              {loading ? "Analyzing..." : "Run AI Audit"}
            </button>

            {file && (
              <button onClick={handleReset} style={activeStyles.resetBtn}>
                Reset
              </button>
            )}
          </div>

          {error && <p style={activeStyles.error}>{error}</p>}
        </div>

        {/* Result Section (ALL ORIGINAL KEPT) */}
        {result && (
          <div style={activeStyles.resultCard}>
            {/* EVERYTHING ORIGINAL REMAINS */}

            {/* ✅ ADMIN PANEL ADDED */}
            {adminMode && (
              <div style={{ marginBottom: 20 }}>
                <h3>Admin Review Panel</h3>
                <textarea
                  placeholder="Write internal review notes..."
                  value={adminNote}
                  onChange={(e) => setAdminNote(e.target.value)}
                  style={{
                    width: "100%",
                    height: 80,
                    marginBottom: 10,
                  }}
                />
              </div>
            )}

            {/* Original Download */}
            <button onClick={downloadReport} style={activeStyles.downloadBtn}>
              Download Audit Report (JSON)
            </button>

            {/* ✅ New Professional Report */}
            <button
              onClick={downloadProfessionalReport}
              style={{
                ...activeStyles.downloadBtn,
                background: "#1e40af",
                marginLeft: 10,
              }}
            >
              Download Professional Report
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

/* ORIGINAL STYLES KEPT */
const styles = { /* --- YOUR ORIGINAL STYLES HERE (UNCHANGED) --- */ };
const darkStyles = {
  ...styles,
  page: { ...styles.page, background: "#0f172a", color: "#fff" },
  uploadCard: { ...styles.uploadCard, background: "#1e293b" },
  resultCard: { ...styles.resultCard, background: "#1e293b" },
  statBox: { ...styles.statBox, background: "#334155" },
  toggleBtn: {
    padding: "8px 15px",
    borderRadius: 8,
    border: "none",
    cursor: "pointer",
  },
};

export default App;
